363→    /** Migrate collection and media databases to scoped storage.
364→     * * Closes the collection, and performs the work in our queue so no
365→     * other code can open the collection while the operation runs. Reopens
366→     * at the end, and rolls back the path change if reopening fails.
367→     */
368→    suspend fun migrateEssentialFiles(context: Context, folders: ValidatedMigrationSourceAndDestination) {
369→        withQueue {
